using System.Drawing;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    private readonly StatusStrip _statusStrip;

    public MyControl()
    {
        // .NET 9: StatusStrip default renderer changed from Professional to System.
        // Explicitly set RenderMode to preserve .NET 8 appearance.
        _statusStrip = new StatusStrip();
        _statusStrip.RenderMode = ToolStripRenderMode.Professional;
        Controls.Add(_statusStrip);
    }

    public string DisplayName { get; set; }
    public int MaxItems { get; set; }

    /// <summary>
    /// Shows a dropdown editor using IWindowsFormsEditorService.
    /// .NET 9 breaking change: DropDownControl(null) now throws ArgumentNullException.
    /// </summary>
    public void ShowDropDown(IWindowsFormsEditorService editorService, Control dropDown)
    {
        if (dropDown is null)
            return;

        editorService.DropDownControl(dropDown);
    }
}

